          { id: 8, levelUk:"★ Проект", levelRu:"★ Проект", textUk:"Генератор та розв'язувач лабіринтів: NxM, рекурсивний backtracking для генерації, DFS для розв'язку. ASCII: # стіна, . шлях, * рішення, S/E. Різні розміри.", textRu:"Генератор лабиринтов (recursive backtracking) + DFS. ASCII: #, ., *, S/E.", starterCode:`import random
def gen_maze(R,C):
    maze=[["#"]*C for _ in range(R)]
    def carve(r,c):
        dirs=[(0,2),(0,-2),(2,0),(-2,0)]; random.shuffle(dirs)
        for dr,dc in dirs:
            nr,nc=r+dr,c+dc
            if 0<=nr<R and 0<=nc<C and maze[nr][nc]=="#":
                maze[r+dr//2][c+dc//2]="."; maze[nr][nc]="."; carve(nr,nc)
    maze[1][1]="."; carve(1,1)
    maze[1][1]="S"; maze[R-2][C-2]="E"
    return maze

def solve(maze):
    R,C=len(maze),len(maze[0])
    start=next((r,c) for r in range(R) for c in range(C) if maze[r][c]=="S")
    end=next((r,c) for r in range(R) for c in range(C) if maze[r][c]=="E")
    vis=set(); path=[]
    def dfs(r,c):
        if (r,c)==end: return True
        for dr,dc in [(0,1),(0,-1),(1,0),(-1,0)]:
            nr,nc=r+dr,c+dc
            if 0<=nr<R and 0<=nc<C and maze[nr][nc] in ".E" and (nr,nc) not in vis:
                vis.add((nr,nc)); path.append((nr,nc))
                if dfs(nr,nc): return True
                path.pop()
        return False
    dfs(*start); return set(path)

maze=gen_maze(11,11); pth=solve(maze)
for r,row in enumerate(maze):
    print("".join("*" if (r,c) in pth and ch=="." else ch for c,ch in enumerate(row)))`}
