          { id:8, levelUk:"★ Проект", levelRu:"★ Проект", textUk:"Клас ComplexNumber з усіма dunder: +,-,*,/ комплексних, abs (модуль), conjugate(), polar(), __str__ ('3+4i'), порівняння за модулем.", textRu:"ComplexNumber: все dunder-операции над комплексными числами, polar(), модуль, сравнение.", starterCode:`import math
class ComplexNumber:
    def __init__(self, re, im=0): self.re=re; self.im=im
    def __add__(self,o): return ComplexNumber(self.re+o.re,self.im+o.im)
    def __sub__(self,o): return ComplexNumber(self.re-o.re,self.im-o.im)
    def __mul__(self,o): return ComplexNumber(self.re*o.re-self.im*o.im,self.re*o.im+self.im*o.re)
    def __truediv__(self,o):
        d=o.re**2+o.im**2
        return ComplexNumber((self.re*o.re+self.im*o.im)/d,(self.im*o.re-self.re*o.im)/d)
    def __abs__(self): return math.sqrt(self.re**2+self.im**2)
    def __eq__(self,o): return abs(self.re-o.re)<1e-9 and abs(self.im-o.im)<1e-9
    def __lt__(self,o): return abs(self)<abs(o)
    def conjugate(self): return ComplexNumber(self.re,-self.im)
    def polar(self): return abs(self), math.atan2(self.im,self.re)
    def __str__(self):
        s=f"{self.re:+.2f}{self.im:+.2f}i" if self.im else f"{self.re:.2f}"
        return s.replace("+","",1) if s.startswith("+") else s

a=ComplexNumber(3,4); b=ComplexNumber(1,-2)
print(f"a={a}, b={b}")
print(f"a+b={a+b}, a*b={a*b}, a/b={a/b}")
print(f"|a|={abs(a)}, conj(a)={a.conjugate()}")`}
