          { id:5, levelUk:"Середньо", levelRu:"Средне", textUk:"Strategy: Sorter зі стратегіями BubbleSort/QuickSort/InsertionSort. Змінюй sorter.strategy на льоту.", textRu:"Strategy: Sorter со стратегиями. Меняй sorter.strategy на лету.", starterCode:`import time,random

class BubbleSort:
    def sort(self,lst):
        a=lst[:]; n=len(a)
        for i in range(n):
            for j in range(n-i-1):
                if a[j]>a[j+1]: a[j],a[j+1]=a[j+1],a[j]
        return a

class QuickSort:
    def sort(self,lst):
        if len(lst)<=1: return lst
        p=lst[len(lst)//2]
        return self.sort([x for x in lst if x<p])+[x for x in lst if x==p]+self.sort([x for x in lst if x>p])

class Sorter:
    def __init__(self,strategy): self.strategy=strategy
    def sort(self,lst): return self.strategy.sort(lst)

data=random.sample(range(1000),500)
s=Sorter(QuickSort())
t0=time.perf_counter(); r=s.sort(data); t1=time.perf_counter()
print(f"Quick: {(t1-t0)*1000:.2f}мс, перші5: {r[:5]}")
s.strategy=BubbleSort()
t0=time.perf_counter(); r=s.sort(data); t1=time.perf_counter()
print(f"Bubble: {(t1-t0)*1000:.2f}мс")`},
          { id:6, levelUk:"Середньо", levelRu:"Средне", textUk:"Command pattern: TextEditor + WriteCmd/DeleteCmd/ReplaceCmd. execute та undo. Зроби 5 дій, потім 3 undo.", textRu:"Command: TextEditor + Write/Delete/Replace. execute и undo. 5 действий, 3 undo.", starterCode:`class TextEditor:
    def __init__(self): self.text=""; self._hist=[]; self._redo=[]
    def execute(self,cmd): cmd.execute(self); self._hist.append(cmd); self._redo.clear()
    def undo(self):
        if self._hist: cmd=self._hist.pop(); cmd.undo(self); self._redo.append(cmd)
    def redo(self):
        if self._redo: cmd=self._redo.pop(); cmd.execute(self); self._hist.append(cmd)

class WriteCmd:
    def __init__(self,t): self.t=t; self.prev=""
    def execute(self,ed): self.prev=ed.text; ed.text+=self.t
    def undo(self,ed): ed.text=self.prev

class ReplaceCmd:
    def __init__(self,old,new): self.old=old;self.new=new;self.prev=""
    def execute(self,ed): self.prev=ed.text; ed.text=ed.text.replace(self.old,self.new)
    def undo(self,ed): ed.text=self.prev

ed=TextEditor()
ed.execute(WriteCmd("Hello, ")); ed.execute(WriteCmd("World"))
ed.execute(ReplaceCmd("World","Python"))
print(f"Текст: {ed.text!r}")
ed.undo(); print(f"Undo: {ed.text!r}")
ed.undo(); print(f"Undo: {ed.text!r}")`},
          { id:7, levelUk:"Складно", levelRu:"Сложно", textUk:"Observer з пріоритетами: підписники отримують події у порядку пріоритету (вищий → перший). @on('event', priority=5).", textRu:"Observer с приоритетами: подписчики вызываются по убыванию приоритета.", starterCode:`class EventEmitter:
    def __init__(self): self._handlers={}
    def on(self,event,priority=0):
        def deco(fn):
            self._handlers.setdefault(event,[]).append((priority,fn))
            self._handlers[event].sort(key=lambda x:-x[0])
            return fn
        return deco
    def emit(self,event,*args):
        for pri,fn in self._handlers.get(event,[]):
            print(f"  [pri={pri}] {fn.__name__}"); fn(*args)

ee=EventEmitter()
@ee.on("click",priority=1)
def logger(x,y): print(f"    Log: click({x},{y})")
@ee.on("click",priority=5)
def validator(x,y): print(f"    Validate: x={x},y={y}")
@ee.on("click",priority=3)
def handler(x,y): print(f"    Handle: ({x},{y})")

print("Подія click:")
ee.emit("click",100,200)`},
          { id:8, levelUk:"★ Проект", levelRu:"★ Проект", textUk:"Повна подієва система: EventEmitter з on/off/emit/once, middleware (лог, фільтр), симуляція UI: кнопки (click/hover/keydown) + 5 хендлерів, хронологічний лог.", textRu:"EventEmitter: on/off/emit/once, middleware, симуляция UI-кнопок, хронологический лог.", starterCode:`from datetime import datetime
class EventEmitter:
    def __init__(self): self._h={}; self._once={}; self._mw=[]; self._log=[]
    def on(self,ev,fn,priority=0):
        self._h.setdefault(ev,[]).append((priority,fn))
        self._h[ev].sort(key=lambda x:-x[0])
    def once(self,ev,fn):
        self._once.setdefault(ev,[]).append(fn)
    def off(self,ev,fn):
        self._h[ev]=[x for x in self._h.get(ev,[]) if x[1]!=fn]
    def use(self,fn): self._mw.append(fn)
    def emit(self,ev,**data):
        entry={"event":ev,"data":data,"time":datetime.now().strftime("%H:%M:%S.%f")[:12]}
        for mw in self._mw:
            if mw(entry) is False: return
        self._log.append(entry)
        for _,fn in self._h.get(ev,[]): fn(**data)
        for fn in self._once.pop(ev,[]): fn(**data)

ee=EventEmitter()
def log_mw(e): print(f"[{e['time']}] {e['event']}: {e['data']}")
ee.use(log_mw)

@lambda _:ee.on("click",_,priority=5) or _
def on_click(x,y,**kw): print(f"  → CLICK at ({x},{y})")

ee.once("keydown", lambda key,**kw: print(f"  → ONCE keydown: {key}"))

print("=== Симуляція UI ===")
ee.emit("click",x=100,y=200)
ee.emit("keydown",key="Enter")
ee.emit("keydown",key="Esc")  # once вже не спрацює
print(f"\nЛог: {len(ee._log)} подій")`}
