            starterCode: `import functools

def safe_call(default=None, exceptions=(Exception,), verbose=True):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            try:
                return func(*args, **kwargs)
            except exceptions as e:
                if verbose:
                    print(f"[safe_call] {func.__name__}: {type(e).__name__}: {e}")
                return default
        return wrapper
    return decorator

@safe_call(default=0, exceptions=(ZeroDivisionError,))
def divide(a, b):
    return a / b

@safe_call(default="?")
def first(lst):
    return lst[0]

print(divide(10, 2))   # → 5.0
print(divide(10, 0))   # → 0 (логує)
print(first([1, 2, 3]))  # → 1
print(first([]))         # → ?`
