            starterCode: `class BankError(Exception):
    pass

class InsufficientFundsError(BankError):
    def __init__(self, amount, balance):
        super().__init__(f"Потрібно {amount}, є лише {balance}")
        self.amount = amount
        self.balance = balance

class NegativeAmountError(BankError):
    pass

class Account:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self._balance = balance
        self.log = []

    def deposit(self, amount):
        if amount <= 0:
            raise NegativeAmountError(f"Сума {amount} має бути > 0")
        self._balance += amount
        self.log.append(f"+{amount}")

    def withdraw(self, amount):
        if amount <= 0:
            raise NegativeAmountError(f"Сума {amount} має бути > 0")
        if amount > self._balance:
            raise InsufficientFundsError(amount, self._balance)
        self._balance -= amount
        self.log.append(f"-{amount}")

    def transfer(self, target, amount):
        self.withdraw(amount)
        target.deposit(amount)

    @property
    def balance(self):
        return self._balance

alice = Account("Аліна", 1000)
bob   = Account("Богдан", 200)

ops = [
    ("deposit",  alice, 500),
    ("withdraw", alice, 300),
    ("transfer", alice, 2000),   # недостатньо
    ("withdraw", bob,  -50),     # від'ємна сума
    ("transfer", alice, 100),
]

for op, acc, amt in ops:
    try:
        if op == "transfer":
            acc.transfer(bob, amt)
        elif op == "deposit":
            acc.deposit(amt)
        elif op == "withdraw":
            acc.withdraw(amt)
        print(f"✅ {op}({amt}) → {acc.owner}: {acc.balance}")
    except BankError as e:
        print(f"❌ {op}({amt}): {e}")

print(f"\\nАліна лог: {alice.log}")
print(f"Богдан лог: {bob.log}")`
