          uk: `<h2>Міні-проект — Algorithm Benchmark Suite</h2>
<h3>Benchmark інфраструктура</h3>
<pre><code>def timed(func, *args, repeat=3):
    times = []
    for _ in range(repeat):
        t0 = time.perf_counter()
        result = func(*args)
        times.append(time.perf_counter() - t0)
    return min(times) * 1000, result   # мс, результат


class BenchmarkSuite:
    def __init__(self, name):
        self.name    = name
        self.results = []

    def add(self, label, func, *args, **kwargs):
        ms, result = timed(func, *args)
        mem = sys.getsizeof(result) if result is not None else 0
        self.results.append({"label": label, "ms": ms, "mem": mem, "result": result})</code></pre>
<h3>Алгоритми сортування</h3>
<pre><code>def insertion_sort(arr):
    arr = list(arr)
    for i in range(1, len(arr)):
        key = arr[i]; j = i - 1
        while j &gt;= 0 and arr[j] &gt; key:
            arr[j+1] = arr[j]; j -= 1
        arr[j+1] = key
    return arr

def merge_sort(arr):
    if len(arr) &lt;= 1: return arr
    mid = len(arr) // 2
    l, r = merge_sort(arr[:mid]), merge_sort(arr[mid:])
    result, i, j = [], 0, 0</code></pre>`,
