        starterCode: `import os
import webbrowser
from pathlib import Path


# ══════════════════════════════════════════════════════════
# HtmlBuilder — fluent API для генерації HTML
# ══════════════════════════════════════════════════════════

class HtmlBuilder:
    def __init__(self, title="Page"):
        self._title = title
        self._body  = []
        self._style = []

    def style(self, css):
        self._style.append(css)
        return self

    def raw(self, html):
        self._body.append(html)
        return self

    def h(self, level, text, **attrs):
        self._body.append(f"<h{level}{_attrs(attrs)}>{text}</h{level}>")
        return self

    def h1(self, text, **attrs): return self.h(1, text, **attrs)
    def h2(self, text, **attrs): return self.h(2, text, **attrs)
    def h3(self, text, **attrs): return self.h(3, text, **attrs)

    def p(self, text, **attrs):
        self._body.append(f"<p{_attrs(attrs)}>{text}</p>")
        return self

    def ul(self, items, **attrs):
        lis = "".join(f"<li>{i}</li>" for i in items)
        self._body.append(f"<ul{_attrs(attrs)}>{lis}</ul>")
        return self

    def ol(self, items, **attrs):
        lis = "".join(f"<li>{i}</li>" for i in items)
        self._body.append(f"<ol{_attrs(attrs)}>{lis}</ol>")
        return self

    def table(self, headers, rows, **attrs):
        ths  = "".join(f"<th>{h}</th>" for h in headers)
        trs  = ""
        for row in rows:
            tds = "".join(f"<td>{c}</td>" for c in row)
            trs += f"<tr>{tds}</tr>"
        self._body.append(
            f"<table{_attrs(attrs)}><thead><tr>{ths}</tr></thead>"
            f"<tbody>{trs}</tbody></table>"
        )
        return self

    def div(self, content, **attrs):
        self._body.append(f"<div{_attrs(attrs)}>{content}</div>")
        return self`
